```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return false;
  }

  try {
    // 3. Read from_account balance
    auto read_result = (sqlgen::read<Account> | sqlgen::where("account_id"_c == from_account_id))(conn);
    if (!read_result) {
      conn->rollback();
      return false;
    }

    auto from_account = read_result.value();

    // 4. Check if sufficient funds exist
    if (from_account.balance < amount) {
      conn->rollback();
      return false;
    }

    // 5. Update from_account (subtract amount with balance check)
    auto update_from_result = (sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) 
                              | sqlgen::where("account_id"_c == from_account_id && "balance"_c >= amount))(conn);
    if (!update_from_result) {
      conn->rollback();
      return false;
    }

    // 6. Update to_account (add amount)
    auto update_to_result = (sqlgen::update<Account>("balance"_c.set("balance"_c + amount)) 
                            | sqlgen::where("account_id"_c == to_account_id))(conn);
    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // 7. Commit transaction if all operations succeed
    auto commit_result = sqlgen::commit(conn);
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // 8. Rollback on any exception
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to connect to "test_db.sqlite"
2. **Transaction Management**: Properly begins transaction with `sqlgen::begin_transaction` and handles commit/rollback
3. **Balance Reading**: Uses `sqlgen::read` with `sqlgen::where` to get the sender's current balance
4. **Sufficient Funds Check**: Validates that the sender's balance >= amount before proceeding
5. **Update Operations**: 
   - First update subtracts amount from sender (with balance check constraint)
   - Second update adds amount to receiver
