  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e, 
      "salary"_e
  ) | sqlgen::inner_join<Employee, "e">("department_id"_d == "department_id"_e);

  auto inner_results = (inner_query | sqlgen::to<std::vector<JoinResult>>())(conn);

  // 4. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
  ) | sqlgen::left_join<Department, "d">("department_id"_e == "department_id"_d);

  auto left_results = (left_query | sqlgen::to<std::vector<JoinResult>>())(conn);

  // 5. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
  ) | sqlgen::right_join<Department, "d">("department_id"_e == "department_id"_d);

  auto right_results = (right_query | sqlgen::to<std::vector<JoinResult>>())(conn);

  // 6. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
  ) | sqlgen::full_join<Department, "d">("department_id"_e == "department_id"_d);

  auto full_results = (full_query | sqlgen::to<std::vector<JoinResult>>())(conn);

  // 7. Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = std::move(inner_results),
      .left_join_results = std::move(left_results),
      .right_join_results = std::move(right_results),
      .full_join_results = std::move(full_results)
  };
}

}  // namespace analyze_department_employees
